import pytest
from typing import Any

def is_palindrome(s: str) -> bool:
    s = s.lower().replace(' ', '')
    return s == s[::-1]

class TestIsPalindrome:

    # Happy path tests
    def test_simple_palindrome(self):
        assert is_palindrome("racecar") == True

    def test_palindrome_with_spaces(self):
        assert is_palindrome("race car") == True

    def test_palindrome_mixed_case(self):
        assert is_palindrome("RaceCar") == True

    def test_palindrome_with_multiple_spaces(self):
        assert is_palindrome("a man a plan a canal panama") == True

    def test_single_character(self):
        assert is_palindrome("a") == True

    def test_empty_string(self):
        assert is_palindrome("") == True

    def test_palindrome_with_numbers(self):
        assert is_palindrome("12321") == True

    def test_palindrome_with_mixed_alphanumeric(self):
        assert is_palindrome("a1b1a") == True

    # Non-palindrome cases (should return False)
    def test_simple_non_palindrome(self):
        assert is_palindrome("hello") == False

    def test_non_palindrome_with_spaces(self):
        assert is_palindrome("hello world") == False

    def test_non_palindrome_mixed_case(self):
        assert is_palindrome("Hello") == False

    # Edge cases
    def test_string_with_only_spaces(self):
        assert is_palindrome("   ") == True

    def test_palindrome_with_special_characters(self):
        # Note: current implementation doesn't handle special chars removal
        assert is_palindrome("a!a") == True  # ! is kept

    def test_palindrome_with_punctuation_and_spaces(self):
        # Current implementation only removes spaces, not punctuation
        assert is_palindrome("a man, a plan, a canal: panama") == False

    def test_very_long_palindrome(self):
        long_palindrome = "a" * 1000 + "b" + "a" * 1000
        assert is_palindrome(long_palindrome) == True

    def test_very_long_non_palindrome(self):
        long_non_palindrome = "a" * 1000 + "bc" + "a" * 1000
        assert is_palindrome(long_non_palindrome) == False

    # Error cases - test type validation
    @pytest.mark.parametrize("invalid_input", [
        None,
        123,
        [],
        {},
        12.34,
        True
    ])
    def test_non_string_inputs(self, invalid_input: Any):
        with pytest.raises(AttributeError):
            is_palindrome(invalid_input)

    # Test specific string methods that might cause issues
    def test_string_with_newlines_and_tabs(self):
        assert is_palindrome("a\nb\ta") == False  # newlines and tabs are kept

    def test_unicode_characters(self):
        assert is_palindrome("αβα") == True  # Greek letters

    def test_palindrome_with_accented_characters(self):
        assert is_palindrome("áéá") == True

# Parametrized tests for multiple cases
@pytest.mark.parametrize("test_string,expected", [
    ("racecar", True),
    ("race car", True),
    ("RaceCar", True),
    ("hello", False),
    ("", True),
    ("a", True),
    ("Aa", True),
    ("ab", False),
    ("aba", True),
    ("abcba", True),
    ("abcde", False),
])
def test_palindrome_parametrized(test_string: str, expected: bool):
    assert is_palindrome(test_string) == expected
